<!DOCTYPE html>
<html>
<head>
  <title>Falling Sand</title>
  <style>
    body {
      background-color: #1e1e1e;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
      font-family: sans-serif;
    }

    #container {
      width: 800px;
      height: 600px;
      position: relative;
    }

    #canvas {
      background-color: #282c34;
      border: none;
      display: block;
    }

    .button {
      background-color: #3e4451;
      color: white;
      padding: 10px 20px;
      border: none;
      cursor: pointer;
      margin: 5px;
      font-size: 16px;
    }

    .button:hover {
      background-color: #434c5e;
    }
  </style>
</head>
<body>
  <div id="container">
    <canvas id="canvas"></canvas>

    <div>
      <button class="button" id="mat-sand">Sand</button>
      <button class="button" id="mat-water">Water</button>
      <button class="button" id="mat-wall">Wall</button>
      <button class="button" id="mat-acid">Acid</button>
      <button class="button" id="mat-empty">Empty (Eraser)</button>
      <button class="button" id="clear">Clear</button>
    </div>
  </div>

  <script>
    const w = 80;
    const h = 60;
    const cellSize = 20;
    const canvasWidth = w * cellSize;
    const canvasHeight = h * cellSize;

    const canvas = document.getElementById('canvas');
    canvas.width = canvasWidth;
    canvas.height = canvasHeight;
    const ctx = canvas.getContext('2d');

    let grid = [];
    for (let y = 0; y < h; y++) {
      grid[y] = [];
      for (let x = 0; x < w; x++) {
        grid[y][x] = 'empty';
      }
    }

    let mouseX = 0;
    let mouseY = 0;
    let isDragging = false;

    const materials = ['empty', 'sand', 'water', 'wall', 'acid'];

    function updateGrid() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          if (grid[y][x] === 'empty') {
            // Check for sand fall
            if (y + 1 < h && grid[y + 1][x] === 'empty') {
              grid[y][x] = 'sand';
              grid[y + 1][x] = 'sand';
            } else if (y + 1 < h && grid[y + 1][x] !== 'empty') {
              // Try to slide diagonally down-left
              if (x - 1 >= 0 && grid[y + 1][x - 1] === 'empty') {
                grid[y][x] = 'sand';
                grid[y + 1][x - 1] = 'sand';
              } else if (x + 1 < w && grid[y + 1][x + 1] === 'empty') {
                grid[y][x] = 'sand';
                grid[y + 1][x + 1] = 'sand';
              }
            }
          } else if (grid[y][x] === 'water') {
            // Water spreads horizontally
            let dx = 0;
            if (x > 0 && grid[y][x - 1] === 'empty') {
              dx = -1;
            } else if (x < w - 1 && grid[y][x + 1] === 'empty') {
              dx = 1;
            }

            if (dx !== 0) {
              grid[y][x + dx] = 'water';
            }
          } else if (grid[y][x] === 'acid') {
            // Acid moves and dissolves
            let dx = 0;
            let dy = 0;

            if (x > 0 && grid[y][x - 1] === 'sand' || grid[y][x - 1] === 'wall') {
              dx = -1;
            } else if (x < w - 1 && grid[y][x + 1] === 'sand' || grid[y][x + 1] === 'wall') {
              dx = 1;
            } else if (y > 0 && grid[y - 1][x] === 'sand' || grid[y - 1][x] === 'wall') {
              dy = -1;
            } else if (y < h - 1 && grid[y + 1][x] === 'sand' || grid[y + 1][x] === 'wall') {
              dy = 1;
            }

            if (dx !== 0 || dy !== 0) {
              grid[y][x + dx] = 'acid';
              grid[y][x + dx] = 'acid'; // Acid moves in the chosen direction.
            }
          }
        }
      }
    }

    function drawGrid() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          const colorMap = {
            'empty': '#282c34',
            'sand': '#ff6b6b',
            'water': '#66b3ff',
            'wall': '#818181',
            'acid': '#ffcc99'
          };

          ctx.fillStyle = colorMap[grid[y][x]];
          ctx.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
        }
      }
    }

    function clearGrid() {
      for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
          grid[y][x] = 'empty';
        }
      }
    }


    window.sim = {
      w,
      h,
      tick: function(n) {
        for (let i = 0; i < n; i++) {
          updateGrid();
        }
      },
      get: function(x, y) {
        if (x >= 0 && x < w && y >= 0 && y < h) {
          return grid[y][x];
        }
        return 'empty';
      },
      set: function(x, y, material) {
        if (x >= 0 && x < w && y >= 0 && y < h) {
          grid[y][x] = material;
        }
      },
      clear: clearGrid,
    };

    document.getElementById('mat-sand').addEventListener('click', () => {
      materials.forEach((material, i) => {
        if (material !== 'empty') {
          window.sim.set(mouseX, mouseY, material);
        }
      });
    });

    document.getElementById('mat-water').addEventListener('click', () => {
      materials.forEach((material, i) => {
        if (material !== 'empty' && material !== 'sand') {
          window.sim.set(mouseX, mouseY, material);
        }
      });
    });

    document.getElementById('mat-wall').addEventListener('click', () => {
      materials.forEach((material, i) => {
        if (material !== 'empty' && material !== 'sand' && material !== 'water') {
          window.sim.set(mouseX, mouseY, material);
        }
      });
    });

    document.getElementById('mat-acid').addEventListener('click', () => {
      materials.forEach((material, i) => {
        if (material !== 'empty' && material !== 'sand' && material !== 'water') {
          window.sim.set(mouseX, mouseY, material);
        }
      });
    });

    document.getElementById('mat-empty').addEventListener('click', () => {
      materials.forEach((material, i) => {
        if (material === 'empty') {
          window.sim.set(mouseX, mouseY, material);
        }
      });
    });

    document.getElementById('clear').addEventListener('click', () => {
      clearGrid();
    });

    canvas.addEventListener('mousedown', (e) => {
      isDragging = true;
      mouseX = Math.round(e.offsetX / cellSize);
      mouseY = Math.round(e.offsetY / cellSize);
    });

    canvas.addEventListener('mouseup', () => {
      isDragging = false;
    });

    canvas.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      mouseX = Math.round(e.offsetX / cellSize);
      mouseY = Math.round(e.offsetY / cellSize);
    });

    function animate() {
      updateGrid();
      drawGrid();
      requestAnimationFrame(animate);
    }

    animate();
  </script>
</body>
</html>
